div.script:
document.addEventListener('DOMContentLoaded', function () {
    var form = document.getElementById('bafB2BRegisterForm');
    var fileInput = document.getElementById('baf_trade_license');
    var websiteInput = document.getElementById('baf_website');

    var countrySelect = document.getElementById('baf_country_id');
    var stateSelect = document.getElementById('baf_state_id');

    function loadStates(countryId, preselectStateId) {
        if (!stateSelect) { return; }
        while (stateSelect.options.length > 1) {
            stateSelect.remove(1);
        }
        if (!countryId) { return; }
        fetch('/b2b/register/states?country_id=' + encodeURIComponent(countryId), {
            method: 'GET',
            credentials: 'same-origin',
            headers: { 'Accept': 'application/json' }
        })
        .then(function (response) {
            if (!response.ok) { throw new Error('states fetch failed'); }
            return response.json();
        })
        .then(function (data) {
            var states = (data && data.states) || [];
            states.forEach(function (state) {
                var opt = document.createElement('option');
                opt.value = state.id;
                opt.textContent = state.name;
                if (preselectStateId && String(state.id) === String(preselectStateId)) {
                    opt.selected = true;
                }
                stateSelect.appendChild(opt);
            });
        })
        .catch(function () { /* leave empty — state stays optional */ });
    }

    if (countrySelect) {
        var initialState = stateSelect ? (stateSelect.getAttribute('data-initial-state-id') || '') : '';
        if (countrySelect.value) {
            loadStates(countrySelect.value, initialState);
        }
        countrySelect.addEventListener('change', function () {
            loadStates(countrySelect.value, '');
        });
    }

    if (form && fileInput) {
        var passwordInput = document.getElementById('baf_password');
        var passwordConfirmInput = document.getElementById('baf_password_confirm');
        form.addEventListener('submit', function (event) {
            var file = fileInput.files && fileInput.files[0];
            if (websiteInput && websiteInput.value) {
                var websiteValue = String(websiteInput.value || '').trim();
                if (websiteValue && !/^[a-zA-Z][a-zA-Z0-9+.-]*:\/\//.test(websiteValue)) {
                    websiteInput.value = 'https://' + websiteValue;
                }
            }
            if (passwordInput && passwordConfirmInput) {
                var pw = String(passwordInput.value || '');
                var pwc = String(passwordConfirmInput.value || '');
                if (pw.length &lt; 8) {
                    event.preventDefault();
                    alert('Das Passwort muss mindestens 8 Zeichen lang sein.');
                    passwordInput.focus();
                    return;
                }
                if (pw !== pwc) {
                    event.preventDefault();
                    alert('Die beiden Passwörter stimmen nicht überein.');
                    passwordConfirmInput.focus();
                    return;
                }
            }
            if (!file) {
                event.preventDefault();
                alert('Bitte laden Sie Ihren Gewerbeschein hoch.');
                return;
            }
            var allowedTypes = ['application/pdf', 'image/jpeg', 'image/png'];
            var allowedExtensions = /\.(pdf|jpg|jpeg|png)$/i;
            var fileName = String(file.name || '');
            if (allowedTypes.indexOf(file.type) === -1 && !allowedExtensions.test(fileName)) {
                event.preventDefault();
                alert('Bitte laden Sie nur PDF, JPG, JPEG oder PNG hoch.');
                return;
            }
            var maxSizeMb = 10;
            var maxSizeBytes = maxSizeMb * 1024 * 1024;
            if (file.size > maxSizeBytes) {
                event.preventDefault();
                alert('Die Datei ist zu groß. Maximal erlaubt sind ' + maxSizeMb + ' MB.');
                return;
            }
        });
    }
});
